import React, { useEffect, useMemo, useState } from 'react';

const STATUS_OPTIONS = [
  { value: 'open', label: 'Abierto' },
  { value: 'in_progress', label: 'En progreso' },
  { value: 'awaiting_client', label: 'Esperando cliente' },
  { value: 'resolved', label: 'Resuelto' },
  { value: 'closed', label: 'Cerrado' }
];

export default function TicketDetail({
  ticket,
  currentUser,
  onSendMessage,
  onChangeStatus,
  onAssign,
  usersByRole,
  loading
}) {
  const [message, setMessage] = useState('');
  const [status, setStatus] = useState(ticket.status);
  const [internal, setInternal] = useState(false);
  const [agentId, setAgentId] = useState(ticket.assignedAgent?._id || '');
  const [programmerId, setProgrammerId] = useState(ticket.assignedProgrammer?._id || '');
  useEffect(() => {
    setStatus(ticket.status);
    setAgentId(ticket.assignedAgent?._id || '');
    setProgrammerId(ticket.assignedProgrammer?._id || '');
    setMessage('');
    setInternal(false);
  }, [ticket._id, ticket.status, ticket.assignedAgent?._id, ticket.assignedProgrammer?._id]);

  const statusOptions = useMemo(() => {
    if (currentUser.role === 'client') {
      return STATUS_OPTIONS.filter((item) => ['open', 'awaiting_client', 'resolved', 'closed'].includes(item.value));
    }
    if (currentUser.role === 'programmer') {
      return STATUS_OPTIONS.filter((item) => ['in_progress', 'awaiting_client', 'resolved'].includes(item.value));
    }
    return STATUS_OPTIONS;
  }, [currentUser.role]);

  const sendMessage = async () => {
    if (!message.trim()) return;
    await onSendMessage(ticket._id, { text: message, internal });
    setMessage('');
  };

  const updateStatus = async () => {
    if (status === ticket.status) return;
    await onChangeStatus(ticket._id, status);
  };

  const updateAssignments = async () => {
    await onAssign(ticket._id, {
      agentId: agentId || undefined,
      programmerId: programmerId || undefined
    });
  };

  return (
    <div className="ticket-detail">
      <header>
        <div>
          <h2>{ticket.title}</h2>
          <p>{ticket.description}</p>
          {ticket.watchers && ticket.watchers.length > 0 && (
            <div className="watcher-list">
              {ticket.watchers.map((member) => (
                <span key={member._id || member.id} className="tag">
                  {member.name || member.email} ({member.role})
                </span>
              ))}
            </div>
          )}
        </div>
        <div className="detail-meta">
          <span className="tag">{ticket.company || 'Sin empresa'}</span>
          <span className="tag">{ticket.priority}</span>
          <span className="tag">{ticket.status}</span>
        </div>
      </header>

      <section className="detail-grid">
        <div>
          <h3>Mensajes</h3>
          <div className="message-feed">
            {ticket.messages.map((msg, index) => (
              <div key={`${msg.createdAt}-${index}`} className={`message-row ${msg.authorRole}`}>
                <div className="message-header">
                  <strong>{msg.authorId?.name || msg.authorRole}</strong>
                  <span>{new Date(msg.createdAt).toLocaleString()}</span>
                </div>
                <p>{msg.text}</p>
                {msg.internal && <span className="tag tag-internal">Interno</span>}
              </div>
            ))}
            {!ticket.messages.length && <div className="message-empty">No hay mensajes en este ticket.</div>}
          </div>
        </div>

        <aside>
          <h3>Acciones</h3>
          <div className="action-block">
            <textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              rows={3}
              placeholder="Escribe una respuesta para el usuario..."
            />
            {currentUser.role !== 'client' && (
              <label className="checkbox-inline">
                <input type="checkbox" checked={internal} onChange={(e) => setInternal(e.target.checked)} />
                Marcar como nota interna
              </label>
            )}
            <button type="button" className="cta-button" onClick={sendMessage} disabled={loading}>
              {loading ? 'Enviando...' : 'Enviar mensaje'}
            </button>
          </div>

          <div className="action-block">
            <label>
              <span>Estado</span>
              <select value={status} onChange={(e) => setStatus(e.target.value)}>
                {statusOptions.map((option) => (
                  <option key={option.value} value={option.value}>
                    {option.label}
                  </option>
                ))}
              </select>
            </label>
            <button type="button" onClick={updateStatus} className="ghost-button">
              Actualizar estado
            </button>
          </div>

          {(currentUser.role === 'admin' || currentUser.role === 'agent') && (
            <div className="action-block">
              <label>
                <span>Asignar asesor</span>
                <select value={agentId} onChange={(e) => setAgentId(e.target.value)}>
                  <option value="">-- sin asignar --</option>
                  {(usersByRole.agent || []).map((user) => (
                    <option key={user.id} value={user.id}>
                      {user.name}
                    </option>
                  ))}
                </select>
              </label>
              <label>
                <span>Asignar programador</span>
                <select value={programmerId} onChange={(e) => setProgrammerId(e.target.value)}>
                  <option value="">-- sin asignar --</option>
                  {(usersByRole.programmer || []).map((user) => (
                    <option key={user.id} value={user.id}>
                      {user.name}
                    </option>
                  ))}
                </select>
              </label>
              <button type="button" onClick={updateAssignments} className="ghost-button">
                Guardar asignaciones
              </button>
            </div>
          )}

          <div className="action-block">
            <h4>Seguimiento</h4>
            <ul className="status-history">
              {(ticket.statusHistory ? ticket.statusHistory.slice().reverse() : []).map((history, index) => (
                <li key={`${history.changedAt}-${index}`}>
                  <strong>{history.status}</strong> por {history.changedBy?.name || 'sistema'} -{' '}
                  {new Date(history.changedAt).toLocaleString()}
                  {history.note && <div>{history.note}</div>}
                </li>
              ))}
            </ul>
          </div>
        </aside>
      </section>
    </div>
  );
}
